#include <SPI.h>
extern uint16_t fft_peak_bin(int16_t*,uint8_t,uint8_t*);
#define N 64
int16_t buf[N];
uint8_t bi=0;
void imu_setup(){SPI.begin();pinMode(10,OUTPUT);}
int16_t imu_z(){return analogRead(A0)-512;}
void led_setup(){pinMode(6,OUTPUT);pinMode(7,OUTPUT);pinMode(8,OUTPUT);}
void led_set(uint8_t lv){
  digitalWrite(6,lv==0?HIGH:LOW);
  digitalWrite(7,lv==1?HIGH:LOW);
  digitalWrite(8,lv>=2?HIGH:LOW);}
void ble_setup(){Serial1.begin(9600);}
void ble_alert(uint8_t b,uint16_t m){
  Serial1.print("{");
  Serial1.print("\"bin\":");Serial1.print(b);
  Serial1.print(",\"mag\":");Serial1.print(m);
  Serial1.println("}");}
float baseline=0;
uint8_t ecnt=0;
void detector_update(uint16_t mag,uint8_t bin){
  if(baseline<1.0f){baseline=(float)mag;return;}
  if(mag>baseline*2.5f){
    ecnt++;if(ecnt>=3){led_set(2);ble_alert(bin,mag);ecnt=0;}
    else led_set(1);}
  else{ecnt=0;led_set(0);baseline=baseline*0.99f+(float)mag*0.01f;}}
unsigned long st=0;
void setup(){Serial.begin(115200);imu_setup();led_setup();ble_setup();}
void loop(){
  if(micros()-st>=1000){st=micros();
    buf[bi++]=imu_z();
    if(bi>=N){bi=0;
      uint8_t pb;
      uint16_t pm=fft_peak_bin(buf,N,&pb);
      detector_update(pm,pb);
      Serial.print(pb);Serial.print(',');Serial.println(pm);}}}
